cat > /tmp/test_metrics.go << 'EOF'
package main

import (
	"fmt"
	"sync"
	"sync/atomic"
)

type Metrics struct {
	mu         sync.RWMutex
	total      int64
	matches    int64
	errors     int64
}

func NewMetrics() *Metrics {
	return &Metrics{}
}

func (m *Metrics) RecordEvaluation() {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.total++
}

func (m *Metrics) RecordMatch() {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.matches++
}

func (m *Metrics) RecordError() {
	m.mu.Lock()
	defer m.mu.Unlock()
	m.errors++
}

func (m *Metrics) GetMetrics() (total, matches, errors int64) {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return m.total, m.matches, m.errors
}

func main() {
	m := NewMetrics()

	// Simulate concurrent evaluation calls
	var wg sync.WaitGroup
	numGoroutines := 10

	for i := 0; i < numGoroutines; i++ {
		wg.Add(1)
		go func(id int) {
			defer wg.Done()
			for j := 0; j < 100; j++ {
				m.RecordEvaluation()
				if j%3 == 0 {
					m.RecordMatch()
				}
				if j%7 == 0 {
					m.RecordError()
				}
			}
		}(i)
	}

	wg.Wait()

	total, matches, errors := m.GetMetrics()
	fmt.Printf("Total evaluations: %d\n", total)
	fmt.Printf("Matches: %d\n", matches)
	fmt.Printf("Errors: %d\n", errors)

	if total == 1000 {
		fmt.Println("✓ Metrics tracking works correctly!")
	}
}
EOF
